def f(n):
    result = []
    i = 0
    while i < n:
        if i % 3 == 0 and i % 5 == 0:
            result.append('FizzBuzz')
        elif i % 3 == 0:
            result.append('Fizz')
        elif i % 5 == 0:
            result.append('Buzz')
        i += 1
    return len([x for x in result if x == 'Fizz'])

print(f(30) + f(15))
```

